'use client'

import { useEffect, useState } from 'react'
import { DashboardHeader } from '@/components/dashboard/header'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { CreditCard, CheckCircle2, AlertTriangle, Zap, Crown, Rocket } from 'lucide-react'

interface CompanySubscription {
    subscription_status: string
    trial_ends_at: string | null
    subscription_plan_id: string | null
}

const plans = [
    {
        name: 'Starter',
        price: '15 000',
        icon: Zap,
        features: ['3 utilisateurs', '1 dépôt', '50 produits', 'Support email', 'Rapports de base'],
        color: 'border-blue-200 bg-blue-50/30',
        btnColor: 'bg-blue-600 hover:bg-blue-700',
    },
    {
        name: 'Professional',
        price: '35 000',
        icon: Crown,
        popular: true,
        features: ['10 utilisateurs', '3 dépôts', '200 produits', 'Support prioritaire', 'Rapports avancés', 'Accès API', 'Multi-dépôt'],
        color: 'border-indigo-300 bg-indigo-50/30',
        btnColor: 'bg-indigo-600 hover:bg-indigo-700',
    },
    {
        name: 'Enterprise',
        price: '75 000',
        icon: Rocket,
        features: ['Utilisateurs illimités', 'Dépôts illimités', 'Produits illimités', 'Support dédié', 'Rapports personnalisés', 'Accès API', 'Formation', 'Branding personnalisé'],
        color: 'border-slate-300 bg-slate-50/30',
        btnColor: 'bg-slate-900 hover:bg-slate-800',
    },
]

export default function SubscriptionPage() {
    const [company, setCompany] = useState<CompanySubscription | null>(null)

    useEffect(() => {
        async function fetchCompany() {
            try {
                const res = await fetch('/api/company')
                const data = await res.json()
                if (data.success) setCompany(data.data)
            } catch (e) {
                console.error(e)
            }
        }
        fetchCompany()
    }, [])

    const statusInfo = {
        trialing: { label: 'Période d\'essai', color: 'bg-amber-50 text-amber-600', icon: AlertTriangle },
        active: { label: 'Actif', color: 'bg-emerald-50 text-emerald-600', icon: CheckCircle2 },
        past_due: { label: 'Paiement en retard', color: 'bg-rose-50 text-rose-600', icon: AlertTriangle },
        canceled: { label: 'Annulé', color: 'bg-slate-100 text-slate-500', icon: AlertTriangle },
    }

    const status = statusInfo[company?.subscription_status as keyof typeof statusInfo] || statusInfo.trialing

    return (
        <div className="flex flex-col min-h-screen bg-[#F8FAFC]">
            <DashboardHeader
                title="Abonnement"
                description="Gérez votre plan et votre facturation"
            />
            <main className="flex-1 p-6 lg:p-10 space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
                {/* Current status */}
                <Card className="rounded-[2.5rem] border-slate-200/60 shadow-sm">
                    <CardContent className="p-8 flex items-center gap-6">
                        <div className={`h-14 w-14 rounded-2xl flex items-center justify-center ${status.color}`}>
                            <status.icon className="h-7 w-7" />
                        </div>
                        <div className="flex-1">
                            <p className="text-[11px] font-black uppercase tracking-[0.2em] text-slate-400">Statut actuel</p>
                            <p className="text-xl font-black text-slate-950">{status.label}</p>
                            {company?.subscription_status === 'trialing' && company?.trial_ends_at && (
                                <p className="text-sm text-slate-500 font-medium mt-1">
                                    Expire le {new Date(company.trial_ends_at).toLocaleDateString('fr-FR', { day: '2-digit', month: 'long', year: 'numeric' })}
                                </p>
                            )}
                        </div>
                    </CardContent>
                </Card>

                {/* Plans */}
                <div>
                    <h2 className="text-2xl font-black text-slate-950 mb-6">Choisissez votre plan</h2>
                    <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3">
                        {plans.map((plan) => (
                            <Card key={plan.name} className={`rounded-[2.5rem] shadow-sm overflow-hidden relative ${plan.color} ${plan.popular ? 'ring-2 ring-indigo-400' : ''}`}>
                                {plan.popular && (
                                    <div className="absolute top-6 right-6">
                                        <Badge className="rounded-xl bg-indigo-600 text-white border-none font-black text-[10px] uppercase tracking-widest px-4 py-1">
                                            Populaire
                                        </Badge>
                                    </div>
                                )}
                                <CardContent className="p-8 space-y-6">
                                    <div className="flex items-center gap-4">
                                        <div className="h-12 w-12 rounded-2xl bg-white/80 flex items-center justify-center shadow-sm">
                                            <plan.icon className="h-6 w-6" />
                                        </div>
                                        <div>
                                            <h3 className="text-xl font-black text-slate-950">{plan.name}</h3>
                                        </div>
                                    </div>
                                    <div>
                                        <span className="text-4xl font-black text-slate-950">{plan.price}</span>
                                        <span className="text-slate-500 font-bold ml-1">FCFA/mois</span>
                                    </div>
                                    <ul className="space-y-3">
                                        {plan.features.map((f) => (
                                            <li key={f} className="flex items-center gap-3 text-sm font-medium text-slate-600">
                                                <CheckCircle2 className="h-4 w-4 text-emerald-500 shrink-0" />
                                                {f}
                                            </li>
                                        ))}
                                    </ul>
                                    <Button className={`w-full rounded-2xl h-12 font-bold text-white ${plan.btnColor}`}>
                                        Sélectionner
                                    </Button>
                                </CardContent>
                            </Card>
                        ))}
                    </div>
                </div>
            </main>
        </div>
    )
}
